esqlQuery.esql:
TS metrics-websphere.otel-default
| WHERE metrics.was_connectionpool_utilization IS NOT NULL
| STATS
    utilization = MAX(AVG_OVER_TIME(metrics.was_connectionpool_utilization))
  BY host.name, attributes.jndiname
// Threshold: alert when average pool utilization exceeds 85%
// Sustained high utilization risks connection exhaustion
// Adjust based on pool sizing and traffic patterns
| WHERE utilization > 85.0
| SORT utilization DESC
